var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>다이브 비정규 좌표</color>     \\n심도 4.8 <color=#ffd34c>유클리드 섹터</color>","JPN":"<color=#ffd34c>ダイブ非正規座標</color>     \\n深度4.8<color=#ffd34c>ユークリッドセクター</color>","ENG":"[[","TWN":"<color=#ffd34c>躍入非正規座標</color>     \\n深度 4.8 <color=#ffd34c>歐幾里得防區</color>","THA":"<color=#ffd34c>พิกัดการไดฟ์แบบไดนามิก</color>     \\nความลึก 4.8 <color=#ffd34c>เซกเตอร์ยูคลิด</color>","VTN":"<color=#ffd34c>Tọa Độ Lặn Động</color>     \\nĐộ Sâu 4.8 <color=#ffd34c>Khu Vực Euclid</color>","SCN":"<color=#ffd34c>跃入非正规坐标</color>     \\n深度 4.8 <color=#ffd34c>欧几里得防区</color>","DEU":"[[","FRA":"<color=#ffd34c>Coordonnées de plongée dynamiques</color>     \\nProfondeur 4,8 <color=#ffd34c>Secteur Euclid</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"잉, 다리 아파~ 제나~","JPN":"え～ん、脚が痛いよ～ジーナ～！","ENG":"*Whine* Zena, my legs hurt.","TWN":"嗚嗚，腿好痛哦~珍娜~"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"조금만 참아, 아이리. 도착한 것 같아.","JPN":"もう少しだけ我慢して、アイリ。到着したみたいだ。","ENG":"Be patient, Irie. We're almost there.","TWN":"再稍微忍耐一下，艾莉，就要到了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"보이는 건 모래먼지밖에 없는데~","JPN":"見えるものなんて砂ぼこりしかないのに～。","ENG":"There's nothing but sand and dust here.","TWN":"這裡明明除了沙和土什麼都看不到~"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"정말 그게 여기 있는 거 맞아? 아이리 님은 그런 게 있다는 얘기 처음 들었다구~","JPN":"本当にそれがここにあるの？\\nアイリ様はそういうのがあるって話、初めて聞いたわ～。","ENG":"Are you sure it's here? Irie has never heard such a thing even exists.","TWN":"真的在這兒嗎？本艾莉可是第一次聽說有這種東西~"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"으음, 그러게......","JPN":"うーん、そうだな……","ENG":"Mm, I don't know.","TWN":"嗯……是啊……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"사실은 나도 캐시가 알려 준 좌표대로만 온 거라서......","JPN":"実は私もキャシーに言われた座標を頼りに来たから……","ENG":"I only followed the coordinates that Cathy gave me.","TWN":"其實我也只是按照凱西給的座標到這兒的……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"다들 믿음이 부족하네요. 전 불확실한 정보는 취급하지 않는 주의에요.","JPN":"二人とも信用してないですね。私は不確かな情報は扱わない主義です。","ENG":"Everyone, have a little bit more faith in me. I always verify my information.","TWN":"大家都沒什麼信心呢，我可是一個不會接受不確切資訊的人喔。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"저기 봐요. 구릉지 사이, 그림자로 가려진 곳에 신기한 게 보이죠?","JPN":"あそこを見て。丘陵地の間、影に遮られた場所に不思議なものが見えるでしょう？","ENG":"Look over there. See that marvelous-looking thing in between the hills, under the shadows?","TWN":"看那裡，丘陵地之間被影子擋住的地方，能看到神奇的東西吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"앗! 정말 있어! 무지 큰 강철 물고기 같아!","JPN":"あっ、本当だ！　超大きな鋼の魚みたい！","ENG":"Ah! You're right! It looks like a gigantic steel fish!","TWN":"啊！真的有耶！像一條巨大的鋼鐵魚一樣！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"되게 신기하게 생겼네......? 차원함선 건조 조약에 저촉되지 않을까?","JPN":"すごく不思議な見た目だね……？\\n次元艦船の建造条約に違反してない？","ENG":"It looks amazing. But what if it's against the dimensional ship construction agreement?","TWN":"它長得好奇特耶？沒有違反次元戰艦建造條約嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"제나도 차암~♪ 그렇게 규칙, 규칙 노래만 부르니까 매번 아이리 님의 트랩에 걸리는 거라구~♪","JPN":"ジーナってば～♪\\nそうやって規則のことばかり言ってるから、毎回アイリ様のトラップに引っかかるのよ～♪","ENG":"Come on, Zena. ♪ Stop playing by the rules, or you'll never get away from Irie's traps. ♪","TWN":"珍娜也真-是的~♪ 妳就是因為這樣只會囉嗦規定、規定，才會每次都中本艾莉的陷阱喔~"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"큭...... 다음엔 절대 안 걸릴 테니까 두고 봐.","JPN":"くうっ……次は絶対引っかからないから！","ENG":"Sheesh, I'll never make that mistake again. Mark my words.","TWN":"可惡……下次我絕對不會再中招了，等著瞧吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"그 멘트도 슬슬 바꿀 때 되지 않았어요? 너무 규칙적이잖아요?","JPN":"そのセリフもそろそろ変え時じゃないでしょうか？　あまりにもワンパターンですよ？","ENG":"Aren't you tired of saying the same thing over and over again? They're too formulaic too, you know.","TWN":"這台詞該換一句了吧？會不會太固定了一點？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"으으......","JPN":"あうぅ……","ENG":"Grr...","TWN":"呃呃……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"그보다 저게 캐시가 그렇게 노래를 부르던 토스트 쉽이야?","JPN":"それより、キャシーがほしがってたトーストシップがあれなの？","ENG":"By the way, Cathy, is that the toast ship you couldn't stop talking about?","TWN":"先不說這個了，那就是凱西一直在囉嗦的逝落艦船嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};